#include <bits/stdc++.h>
using namespace std;
int binarySearch(vector<int>& arr, int target){
    int l=0, r=arr.size()-1;
    while(l<=r){
        int mid = l + (r-l)/2;
        if(arr[mid]==target) return mid;
        else if(arr[mid]<target) l=mid+1;
        else r=mid-1;
    }
    return -1;
}
int main(){
    int n; cin>>n;
    vector<int> arr(n);
    for(int i=0;i<n;i++) cin>>arr[i];
    int target; cin>>target;
    cout<<binarySearch(arr, target);
}
